svg.script:
// The 4 possible routes: 0=euc1-0 (upper left), 1=euc1-1 (lower left), 2=euw1-0 (upper right), 3=euw1-1 (lower right)
var PATHS = [
"M540,220 L540,440 L410,440 L400,440 L360,440 L360,320 L320,320 L240,320 L200,320",
"M540,220 L540,440 L500,440 L410,440 L400,440 L360,440 L360,560 L320,560 L240,560 L200,560",
"M540,220 L540,440 L580,440 L670,440 L680,440 L720,440 L720,320 L760,320 L840,320 L880,320",
"M540,220 L540,440 L580,440 L670,440 L680,440 L720,440 L720,500 L720,560 L760,560 L840,560 L880,560"
];

var DUR = 0.5;
var DEFAULT_STATUS_URL = (function () {
  try {
    if (window.location.protocol === "http:" || window.location.protocol === "https:") {
      return "http://" + window.location.hostname + "/proxy";
    }
  } catch (e) {}
  return "http://ac9ad246b8784eced.awsglobalaccelerator.com/proxy";
})();
var URL_PARAM = (function () {
  try {
    var params = new URLSearchParams(window.location.search);
    return params.get("url");
  } catch (e) {
    return null;
  }
})();
var STATUS_URL = URL_PARAM || DEFAULT_STATUS_URL;

// If loaded directly from the filesystem (no http/https) and no explicit
// ?url= override was given, there is nothing to fetch from. In that case
// pick a random region for each interval instead of calling the status URL.
var USE_RANDOM = (window.location.protocol === "file:") && !URL_PARAM;

// counts[index] = how often this region's instance has been seen, plus its latest instance name
var REGION_CODES = ["euc1-0", "euc1-1", "euw1-0", "euw1-1"];
var counts = [0, 0, 0, 0];
var instanceNames = [null, null, null, null];
var total = 0;

function regionToIndex(name) {
  if (!name) return null;
  if (name.endsWith("euc1-0")) return 0;
  if (name.endsWith("euc1-1")) return 1;
  if (name.endsWith("euw1-0")) return 2;
  if (name.endsWith("euw1-1")) return 3;
  return null;
}

function animateAlong(index) {
  var dot = document.getElementById("traffic-dot");
  var old = dot.querySelector("animateMotion");
  if (old) dot.removeChild(old);

  var anim = document.createElementNS("http://www.w3.org/2000/svg", "animateMotion");
  anim.setAttribute("dur", DUR + "s");
  anim.setAttribute("begin", "indefinite");
  anim.setAttribute("repeatCount", "1");
  anim.setAttribute("fill", "freeze");
  anim.setAttribute("path", PATHS[index]);
  dot.appendChild(anim);
  anim.beginElement();
}

function updateStats(index, name) {
  counts[index]++;
  instanceNames[index] = name;
  total++;
  document.getElementById("total-counter").textContent = total;
  var euc1Total = counts[0] + counts[1];
  var euw1Total = counts[2] + counts[3];

  for (var i = 0; i < 4; i++) {
    document.getElementById("cnt-" + i).textContent = counts[i];
    var sideTotal = (i < 2) ? euc1Total : euw1Total;
    var weight = sideTotal > 0 ? Math.round((counts[i] / sideTotal) * 256) : 0;
    document.getElementById("pct-" + i).textContent = weight;
  }
  document.getElementById("cnt-euc1").textContent = euc1Total;
  document.getElementById("cnt-euw1").textContent = euw1Total;
  document.getElementById("pct-euc1").textContent = (total > 0 ? (euc1Total / total * 100) : 0).toFixed(1) + "%";
  document.getElementById("pct-euw1").textContent = (total > 0 ? (euw1Total / total * 100) : 0).toFixed(1) + "%";
}

function runOnce() {
  if (USE_RANDOM) {
    var index = Math.floor(Math.random() * 4);
    var name = "random-" + REGION_CODES[index];
    animateAlong(index);
    // Only update counters/percentages once the traffic dot has
    // reached the end of its track.
    setTimeout(function () {
      updateStats(index, name);
    }, DUR * 1000);
    setTimeout(runOnce, DUR * 1000);
    return;
  }

  fetch(STATUS_URL)
    .then(function (res) { return res.text(); })
    .then(function (text) {
      var m = text.match(/<!--\s*Instance Name\s*-->\s*<h2>([^<]*)<\/h2>/i);
      var name = m ? m[1].trim() : null;
      var index = regionToIndex(name);
      if (index !== null) {
        animateAlong(index);
        // Only update counters/percentages once the traffic dot has
        // reached the end of its track.
        setTimeout(function () {
          updateStats(index, name);
        }, DUR * 1000);
      } else {
        console.warn("Could not determine region from response:", name);
      }
    })
    .catch(function (err) {
      console.error("Status fetch failed:", err);
    })
    .then(function () {
      setTimeout(runOnce, DUR * 1000);
    });
}

// Wait 3s after the dashboard becomes visible before starting the traffic animation.
setTimeout(runOnce, 3000);
